+import { NonExhaustiveError } from './errors';
+import { matchPattern } from './internals/helpers';
+import * as symbols from './internals/symbols';
+import type { MatchEach } from './types/MatchEach';
+
+type Clause = { args: any[]; kind: 'with' | 'when' };
+type Operation = Clause | { kind: 'tap'; callback: (result: unknown) => void };
+
+/** Creates a pattern matching expression which evaluates every matching clause. */
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, output>;
+/** Creates a reusable pattern matching expression. */
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach(value?: unknown): MatchEach<any, any> {
+  return new MatchEachExpression([], arguments.length === 0 ? undefined : value) as any;
+}
+
+class MatchEachExpression {
+  constructor(private operations: Operation[], private value?: unknown) {}
+
+  with(...args: any[]) {
+    return new MatchEachExpression([...this.operations, { kind: 'with', args }], this.value);
+  }
+
+  when(...args: any[]) {
+    return new MatchEachExpression([...this.operations, { kind: 'when', args }], this.value);
+  }
+
+  tap(callback: (result: unknown) => void) {
+    return new MatchEachExpression([...this.operations, { kind: 'tap', callback }], this.value);
+  }
+
+  private evaluate(value: unknown, fallback?: (value: unknown) => unknown, partial = false): unknown[] | undefined {
+    const results: unknown[] = [];
+    for (const operation of this.operations) {
+      if (operation.kind === 'tap') {
+        results.forEach(operation.callback);
+        continue;
+      }
+      if (operation.kind === 'when') {
+        const [predicate, handler] = operation.args;
+        if (predicate(value)) results.push(handler(value));
+        continue;
+      }
+      const args = operation.args;
+      const handler = args[args.length - 1];
+      const patterns = [args[0]];
+      let predicate: ((value: unknown) => unknown) | undefined;
+      if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+      else if (args.length > 2) patterns.push(...args.slice(1, -1));
+
+      let hasSelections = false;
+      const selected: Record<string, unknown> = {};
+      const select = (key: string, selection: unknown) => {
+        hasSelections = true;
+        selected[key] = selection;
+      };
+      const matched = patterns.some((pattern) => matchPattern(pattern, value, select)) && (!predicate || Boolean(predicate(value)));
+      if (matched) {
+        const selections = hasSelections
+          ? symbols.anonymousSelectKey in selected ? selected[symbols.anonymousSelectKey] : selected
+          : value;
+        results.push(handler(selections, value));
+      }
+    }
+    if (results.length) return results;
+    if (fallback) return [fallback(value)];
+    return partial ? undefined : defaultCatcher(value);
+  }
+
+  otherwise(handler: (value: unknown) => unknown) {
+    return this.evaluate(this.value, handler);
+  }
+  exhaustive(handler?: (value: unknown) => unknown) {
+    return this.evaluate(this.value, handler);
+  }
+  run() { return this.evaluate(this.value); }
+  toFunction() { return (input: unknown) => this.evaluate(input) as unknown[]; }
+  toExhaustiveFunction() { return (input: unknown) => this.evaluate(input) as unknown[]; }
+  toPartialFunction() { return (input: unknown) => this.evaluate(input, undefined, true); }
+  returnType() { return this; }
+  narrow() { return this; }
